package pe.org.camaracomercioica.protestos.service; import lombok.RequiredArgsConstructor; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import pe.org.camaracomercioica.protestos.dto.*; import pe.org.camaracomercioica.protestos.exception.BadRequestException; import pe.org.camaracomercioica.protestos.model.*; import pe.org.camaracomercioica.protestos.repository.*; import java.security.SecureRandom; import java.util.List; @Service @RequiredArgsConstructor public class CatalogoService { private final EntidadFinancieraRepository entidades;private final AnalistaRepository analistas;private final UsuarioRepository usuarios;private final RolRepository roles;private final PasswordEncoder encoder; public List<EntidadResponse> entidades(){return entidades.findAll().stream().map(e->new EntidadResponse(e.getId(),e.getRuc(),e.getRazonSocial(),e.getContacto(),e.getEmail(),e.isActivo())).toList();} @Transactional public EntidadResponse crear(EntidadRequest r){if(entidades.existsByRuc(r.ruc()))throw new BadRequestException("El RUC ya existe");var e=new EntidadFinanciera();e.setRuc(r.ruc());e.setRazonSocial(r.razonSocial().trim());e.setContacto(r.contacto());e.setEmail(r.email());e=entidades.save(e);return new EntidadResponse(e.getId(),e.getRuc(),e.getRazonSocial(),e.getContacto(),e.getEmail(),e.isActivo());}public List<AnalistaResponse> analistas(){return analistas.findAll().stream().map(this::map).toList();}@Transactional public AnalistaResponse crear(AnalistaRequest r){if(analistas.existsByCodigo(r.codigo())||usuarios.findByEmailIgnoreCase(r.email()).isPresent())throw new BadRequestException("Email o código ya existe");var u=new Usuario();u.setNombreCompleto(r.nombre());u.setEmail(r.email());u.setPasswordHash(encoder.encode("Demo!"+new SecureRandom().nextInt(100000)+"Aa"));u.setRol(roles.findByNombre("ANALISTA").orElseThrow(()->new BadRequestException("Rol ANALISTA no configurado")));u=usuarios.save(u);var a=new Analista();a.setUsuario(u);a.setCodigo(r.codigo());return map(analistas.save(a));}private AnalistaResponse map(Analista a){return new AnalistaResponse(a.getId(),a.getCodigo(),a.getUsuario().getNombreCompleto(),a.getUsuario().getEmail(),a.isDisponible());}}
